def extract_design_elements(design_descriptions):
    """
    Extracts common graphic design elements from a list of descriptions.
    Returns a dictionary of unique elements found in the descriptions.
    """
    elements = []
    for description in design_descriptions:
        # Define keywords for common design elements
        keywords = ['typography', 'geometric', 'bold', 'layout', 'color', 'illustration', 'minimalist', 'contrast']
        # Check for keyword matches in each description
        for word in keywords:
            if word in description.lower():
                if word not in elements:
                    elements.append(word)
    return {"elements": elements}

# Example usage:
descriptions = [
    "Modern geometric forms and bold typefaces",
    "Clean layout with minimalist color scheme",
    "High-contrast illustration for emphasis"
]
print(extract_design_elements(descriptions))
# Output: {'elements': ['geometric', 'bold', 'layout', 'minimalist', 'color', 'contrast', 'illustration']}
